function AQuiz({onD}){
  const[questions]=useState(()=>pickQuestions());
  const[s,ss]=useState(0);
  const[a,sa]=useState([]);
  const[am,sam]=useState(null);
  const p=questions[s];
  const total=questions.length;
  const pk=sd=>{
    sam(sd);
    const choice=sd==="a"?p.a.l:p.b.l;
    track("archquiz_answer",{q:s+1,question:p.q,axis:p.axis,choice});
    setTimeout(()=>{
      const n=[...a,sd];
      if(n.length>=total){track("archquiz_complete");onD({answers:n,questions})}
      else{sa(n);ss(s+1);sam(null)}
    },280);
  };
  if(!p)return null;
  // Bold first significant noun/verb in the question
  const renderQuestion=(text)=>{
    // Find first comma/period to bold the first phrase if it's a setup
    const parts=text.split(/(\.|,|—|:)/);
    if(parts.length>=2){
      return <>
        <b style={{fontWeight:600}}>{parts[0]}</b>
        {parts.slice(1).join("")}
      </>;
    }
    return text;
  };
  return <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",padding:"24px"}}>
    <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:28}}>
      <div style={{flex:1,height:4,background:C.border,borderRadius:2,overflow:"hidden"}}>
        <div style={{width:`${(s/total)*100}%`,height:"100%",background:C.accent,borderRadius:2,transition:"width .3s"}}/>
      </div>
      <span style={{fontFamily:"Montserrat,sans-serif",fontSize:13,color:C.muted,fontWeight:600}}>{s+1}/{total}</span>
    </div>
    <div style={{flex:1,display:"flex",flexDirection:"column",justifyContent:"center",gap:24,maxWidth:480,margin:"0 auto",width:"100%"}}>
      <div style={{textAlign:"center"}}>
        <div style={{fontSize:48,marginBottom:14,lineHeight:1}}>{p.emoji||"🔮"}</div>
        <p style={{fontFamily:"Cormorant Garamond,serif",fontSize:22,color:C.ink,fontStyle:"italic",margin:0,lineHeight:1.45,padding:"0 8px"}}>{renderQuestion(p.q)}</p>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        {["a","b"].map(sd=>{
          const o=p[sd],iA=am===sd,iO=am&&am!==sd;
          return <button key={sd} onClick={()=>!am&&pk(sd)} style={{background:"#fff",border:`2px solid ${iA?C.accent:C.border}`,borderRadius:14,padding:"20px 24px",cursor:am?"default":"pointer",textAlign:"center",transition:"all .25s",transform:iA?"scale(1.03)":iO?"scale(.97)":"none",opacity:iO?.4:1}}>
            <span style={{fontFamily:"Cormorant Garamond,serif",fontSize:20,fontWeight:500,color:C.ink}}>{o.l}</span>
          </button>
        })}
      </div>
    </div>
  </div>
}

function ProfileScr({arch,coins,bdgs,iq,learned,curBdg,expanded,setExpanded,go,onLearn,onBdg,onShare}){
  // Calculate total points and level
  const totalCorrect=bdgs.reduce((s,b)=>s+(b.qs||0),0);
  const totalCards=learned;
  const totalPoints=calcPoints(totalCards,totalCorrect);
  const level=calcLevel(totalPoints);
  const nextLevel=LEVELS[level.idx+1];
  const totalCardsMax=BADGE_DATA.reduce((s,b)=>s+(b.cards?.length||0),0);
  const totalQuizMax=BADGE_DATA.reduce((s,b)=>s+(b.quiz?.length||0),0);
  // Recommended badge for this archetype
  const recBadgeIdx=arch?.id?ARCH_TO_BADGE[arch.id]??0:0;
  const recBadge=BADGE_DATA[recBadgeIdx];
  const archHook=arch?.id?ARCH_LEARN_HOOK[arch.id]:"Опануй секрети кулінарії";
  const recBadgeDone=bdgs[recBadgeIdx]?.done;
  // If recommended badge is done, show next un-done badge
  const targetBadgeIdx=recBadgeDone?bdgs.findIndex(b=>!b.done):recBadgeIdx;
  const targetBadge=targetBadgeIdx>=0?BADGE_DATA[targetBadgeIdx]:null;
  // Hook adapts: archetype hook for recommended, generic for fallback, congrats when all done
  const learnHook=targetBadgeIdx<0?"🎓 Всі знання здобуто! Готовий до Кулінарного IQ":targetBadgeIdx===recBadgeIdx?archHook:`Наступний крок — ${targetBadge?.n}`;

  return <div style={{minHeight:"100vh",padding:"24px 24px 90px",maxWidth:480,margin:"0 auto"}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
      <div style={{display:"flex",alignItems:"center",gap:6}}>
        <span style={{fontSize:14}}>{level.e}</span>
        <span style={{fontFamily:"Montserrat,sans-serif",fontSize:11,color:C.ink,fontWeight:600}}>{level.n}</span>
      </div>
      <Cn n={coins}/>
    </div>
    <button onClick={()=>setExpanded(!expanded)} style={{width:"100%",background:C.ink,borderRadius:14,padding:"18px",marginBottom:2,border:"none",cursor:"pointer",textAlign:"left",display:"flex",alignItems:"center",gap:14}}>
      <span style={{fontSize:44}}>{arch.e}</span>
      <div style={{flex:1}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:9,fontWeight:600,letterSpacing:2,color:C.gold,margin:"0 0 3px"}}>АРХЕТИП</p><h2 style={{fontFamily:"Cormorant Garamond,serif",fontSize:22,fontWeight:400,color:C.paper,margin:0}}>{arch.n}</h2></div>
      <span style={{color:C.muted,fontSize:16}}>{expanded?"▲":"▼"}</span>
    </button>
    {expanded&&<div style={{background:C.ink,borderRadius:"0 0 14px 14px",padding:"0 18px 18px",marginBottom:14}}>
      <p style={{fontFamily:"Cormorant Garamond,serif",fontSize:15,color:C.paper+"cc",lineHeight:1.6,margin:"0 0 14px",fontStyle:"italic"}}>{arch.d}</p>
      {arch.spectrum&&<div style={{marginBottom:14}}>
        {[{k:"sCr",c:C.accent},{k:"rSp",c:C.accent2},{k:"pA",c:C.accent3},{k:"cE",c:C.gold}].map(({k,c})=>{
          const sp=arch.spectrum[k];if(!sp||sp.total===0)return null;
          const leftPct=Math.round((sp.left/sp.total)*100);
          return <div key={k} style={{marginBottom:8}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
              <span style={{fontFamily:"Montserrat,sans-serif",fontSize:9,color:C.paper+"99"}}>{sp.leftLabel} {leftPct}%</span>
              <span style={{fontFamily:"Montserrat,sans-serif",fontSize:9,color:C.paper+"99"}}>{100-leftPct}% {sp.rightLabel}</span>
            </div>
            <div style={{height:4,background:C.paper+"15",borderRadius:2,overflow:"hidden",position:"relative"}}>
              <div style={{position:"absolute",left:0,top:0,height:"100%",width:`${leftPct}%`,background:c,borderRadius:2}}/>
            </div>
          </div>
        })}
      </div>}
      <div style={{background:C.gold+"15",borderRadius:10,padding:"10px 14px",marginBottom:8}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1.5,color:C.gold,margin:"0 0 4px"}}>⚡ СУПЕРСИЛА</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.paper,margin:0,lineHeight:1.4}}>{arch.sup}</p></div>
      {arch.punkt&&<div style={{background:C.accent3+"25",borderRadius:10,padding:"10px 14px",marginBottom:8}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1.5,color:"#7BB6E0",margin:"0 0 4px"}}>🎯 ТВІЙ ПУНКТИК</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.paper,margin:0,lineHeight:1.4}}>{arch.punkt}</p></div>}
      {arch.pravda&&<div style={{background:C.accent2+"25",borderRadius:10,padding:"10px 14px",marginBottom:8}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1.5,color:"#5EBE94",margin:"0 0 4px"}}>🤫 ЩИРА ПРАВДА</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.paper,margin:0,lineHeight:1.4}}>{arch.pravda}</p></div>}
      {arch.gniv&&<div style={{background:C.accent+"25",borderRadius:10,padding:"10px 14px",marginBottom:8}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1.5,color:"#E07444",margin:"0 0 4px"}}>😤 ТВІЙ ГНІВ</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.paper,margin:0,lineHeight:1.4}}>{arch.gniv}</p></div>}
      <div style={{background:C.paper+"08",borderRadius:10,padding:"10px 14px",marginTop:10,border:`1px solid ${C.paper}15`}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1.5,color:C.muted,margin:"0 0 4px"}}>🌗 ТІНЬ: {arch.sh}</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:13,color:C.paper+"bb",margin:0,fontStyle:"italic",lineHeight:1.4}}>{arch.shd}</p></div>
      <button onClick={onShare} style={{width:"100%",background:C.gold+"20",border:`1px solid ${C.gold}40`,borderRadius:10,padding:"12px",cursor:"pointer",marginTop:12,fontFamily:"Montserrat,sans-serif",fontSize:12,fontWeight:600,color:C.gold}}>📤 Поділитись архетипом</button>
    </div>}
    {!expanded&&<div style={{height:14}}/>}

    {/* LEVEL PROGRESS — replaces IQ */}
    <div style={{background:"#fff",borderRadius:14,padding:"16px 18px",border:`1px solid ${C.border}`,marginBottom:14}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:14}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:22}}>{level.e}</span>
          <span style={{fontFamily:"Cormorant Garamond,serif",fontSize:18,fontWeight:600,color:C.ink}}>{level.n}</span>
        </div>
        <span style={{fontFamily:"Montserrat,sans-serif",fontSize:18,fontWeight:700,color:C.accent}}>{totalPoints}</span>
      </div>
      {/* Multi-level progress bar */}
      <div style={{position:"relative",height:8,background:C.border,borderRadius:4,marginBottom:18}}>
        <div style={{position:"absolute",left:0,top:0,height:"100%",width:`${Math.min(100,(totalPoints/750)*100)}%`,background:`linear-gradient(90deg,${C.accent2},${C.accent})`,borderRadius:4}}/>
        {LEVELS.map((lv,i)=>{
          if(i===0)return null;
          const pct=(lv.min/750)*100;
          const reached=totalPoints>=lv.min;
          return <div key={i} style={{position:"absolute",left:`${pct}%`,top:"50%",transform:"translate(-50%,-50%)",width:12,height:12,borderRadius:"50%",background:reached?C.accent:"#fff",border:`2px solid ${reached?C.accent:C.border}`,zIndex:1}}/>
        })}
      </div>
      {/* Level labels */}
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:12,marginTop:-10}}>
        {LEVELS.map((lv,i)=><div key={i} style={{textAlign:"center",flex:1}}>
          <div style={{fontSize:12,opacity:totalPoints>=lv.min?1:0.3}}>{lv.e}</div>
        </div>)}
      </div>
      {/* Next level info */}
      {nextLevel?<p style={{fontFamily:"Montserrat,sans-serif",fontSize:11,color:C.muted,margin:"0 0 10px",textAlign:"center"}}>↗ <b style={{color:C.ink}}>{nextLevel.min-totalPoints}</b> балів до <b style={{color:C.ink}}>{nextLevel.n}</b></p>:<p style={{fontFamily:"Montserrat,sans-serif",fontSize:11,color:C.gold,margin:"0 0 10px",textAlign:"center",fontWeight:600}}>🎓 Готовий до Кулінарного IQ</p>}
      {/* Stats */}
      <div style={{display:"flex",justifyContent:"space-around",borderTop:`1px solid ${C.border}`,paddingTop:10}}>
        <div style={{textAlign:"center"}}>
          <div style={{fontFamily:"Montserrat,sans-serif",fontSize:13,color:C.ink,fontWeight:600}}>📚 {totalCards}/{totalCardsMax}</div>
          <div style={{fontFamily:"Montserrat,sans-serif",fontSize:9,color:C.muted}}>карток пройдено</div>
        </div>
        <div style={{textAlign:"center"}}>
          <div style={{fontFamily:"Montserrat,sans-serif",fontSize:13,color:C.ink,fontWeight:600}}>🧠 {totalCorrect}/{totalQuizMax}</div>
          <div style={{fontFamily:"Montserrat,sans-serif",fontSize:9,color:C.muted}}>правильних</div>
        </div>
      </div>
    </div>

    {/* LEARN BUTTON — archetype-specific */}
    {targetBadge&&<button onClick={()=>onLearn(targetBadgeIdx)} style={{width:"100%",background:C.accent,color:"#fff",border:"none",borderRadius:14,padding:"18px 16px",cursor:"pointer",marginBottom:14,textAlign:"left"}}>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:6}}>
        <span style={{fontSize:24}}>{targetBadge.e}</span>
        <span style={{fontFamily:"Montserrat,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1.5,opacity:0.85}}>ТВІЙ ШЛЯХ ЗНАНЬ</span>
      </div>
      <p style={{fontFamily:"Cormorant Garamond,serif",fontSize:18,fontWeight:500,margin:"0 0 6px",lineHeight:1.3}}>{learnHook}</p>
      <p style={{fontFamily:"Montserrat,sans-serif",fontSize:11,opacity:0.85,margin:0}}>{targetBadge.n} · 10 карток · 7 питань</p>
    </button>}

    <p style={{fontFamily:"Montserrat,sans-serif",fontSize:10,fontWeight:600,letterSpacing:2,color:C.muted,marginBottom:10}}>ВСІ БЕЙДЖІ ({bdgs.filter(b=>b.done).length}/{bdgs.length})</p>
    <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:6,marginBottom:20}}>
      {bdgs.map((b,i)=>{
        const isRec=i===recBadgeIdx&&!b.done;
        return <button key={b.id} onClick={()=>onBdg(b,i)} style={{background:b.done?"#fff":isRec?C.accent+"15":C.paper2,border:`1px solid ${b.done?C.accent2+"40":isRec?C.accent+"60":C.border}`,borderRadius:12,padding:"10px 2px",cursor:"pointer",textAlign:"center",opacity:b.done?1:1}}>
          <div style={{fontSize:24}}>{b.e}</div>
          <div style={{fontFamily:"Montserrat,sans-serif",fontSize:7,color:b.done?C.ink:C.ink,marginTop:2}}>{b.n}</div>
          {b.done&&<div style={{fontFamily:"Montserrat,sans-serif",fontSize:7,color:C.accent2,marginTop:1}}>✅ {b.qs}/7</div>}
          {!b.done&&isRec&&<div style={{fontFamily:"Montserrat,sans-serif",fontSize:6,color:C.accent,marginTop:1,fontWeight:600}}>★ для тебе</div>}
          {!b.done&&!isRec&&<div style={{fontFamily:"Montserrat,sans-serif",fontSize:6,color:C.muted,marginTop:1}}>10 карток</div>}
        </button>
      })}
    </div>
    <BNav a="profile" go={go}/>
  </div>
}

function BModal({b,bi,curBdg,onL,onQ,onC}){const done=b.done;
  return <div style={{position:"fixed",inset:0,display:"flex",alignItems:"center",justifyContent:"center",zIndex:200,background:"rgba(0,0,0,.4)"}} onClick={onC}><div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:20,padding:"28px 24px",maxWidth:320,width:"90%",textAlign:"center"}}><div style={{fontSize:52,marginBottom:8}}>{b.e}</div><h3 style={{fontFamily:"Cormorant Garamond,serif",fontSize:22,color:C.ink,margin:"0 0 4px"}}>{b.n}</h3><p style={{fontFamily:"Montserrat,sans-serif",fontSize:11,color:C.muted,margin:"0 0 16px"}}>{b.cat}</p>{done&&<div style={{background:C.accent2+"12",borderRadius:10,padding:"8px",marginBottom:12}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:12,color:C.accent2,margin:0}}>✅ Квіз: {b.qs}/7</p></div>}<div style={{display:"flex",flexDirection:"column",gap:8}}><button onClick={onL} style={{background:C.accent,color:"#fff",border:"none",borderRadius:10,padding:"14px",cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontSize:13,fontWeight:600}}>📚 Навчання (10 карток)</button><button onClick={onQ} style={{background:C.ink,color:C.paper,border:"none",borderRadius:10,padding:"14px",cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontSize:13,fontWeight:600}}>🧠 Квіз (7 питань)</button></div><button onClick={onC} style={{background:"transparent",border:"none",color:C.muted,marginTop:12,cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontSize:12}}>Закрити</button></div></div>}

function Learn({badgeIdx,coins,setCn,onD,go}){const bd=BADGE_DATA[badgeIdx];const cards=bd?bd.cards:[];const[i,si]=useState(0);const[kn,skn]=useState(0);const[dk,sdk]=useState(0);const[am,sam]=useState(false);const[bt,sbt]=useState(false);const[exp,sexp]=useState(false);const F=5,lm=bt?cards.length:F,c=cards[i],isPay=i>=lm&&!bt;
  useEffect(()=>{track("learn_start",{badge:bd?.id})},[]);
  const ans=k=>{sexp(false);track("learn_card",{badge:bd?.id,card:i+1,hook:c?.hook,knew:k});if(k)skn(v=>v+1);else sdk(v=>v+1);sam(true);setTimeout(()=>{const nx=i+1;if(nx>=lm&&nx<cards.length&&!bt){si(nx);sam(false)}else if(nx>=cards.length){track("learn_complete",{badge:bd?.id});onD({knew:k?kn+1:kn,didnt:k?dk:dk+1,total:nx,allDone:true})}else{si(nx);sam(false)}},400)};
  if(isPay)return <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"40px 24px",textAlign:"center"}}><div style={{fontSize:48,marginBottom:16}}>🔒</div><h2 style={{fontFamily:"Cormorant Garamond,serif",fontSize:24,color:C.ink,margin:"0 0 6px"}}>{F} карток пройдено!</h2><p style={{fontFamily:"Montserrat,sans-serif",fontSize:13,color:C.muted,margin:"0 0 20px"}}>Знав: {kn} · Нового: {dk}</p><div style={{display:"flex",flexDirection:"column",gap:10,width:"100%",maxWidth:300}}><button onClick={()=>{if(coins>=20){setCn(c=>c-20);sbt(true)}}} style={{background:C.gold+"15",border:`2px solid ${C.gold}`,borderRadius:12,padding:"14px",cursor:coins>=20?"pointer":"default",opacity:coins>=20?1:.5}}><span style={{fontFamily:"Montserrat,sans-serif",fontSize:13,fontWeight:600,color:C.gold}}>🪙 Ще 5 за 20 монет ({coins})</span></button><button style={{background:C.accent,color:"#fff",border:"none",borderRadius:12,padding:"14px",cursor:"pointer"}}><span style={{fontFamily:"Montserrat,sans-serif",fontSize:13,fontWeight:600}}>⭐ Підписка</span></button><button onClick={()=>onD({knew:kn,didnt:dk,total:i,allDone:false})} style={{color:C.muted,border:"none",background:"transparent",padding:"10px",cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontSize:12}}>Завтра →</button></div></div>;
  if(!c)return null;
  return <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",padding:"24px",paddingBottom:80}}><div style={{display:"flex",alignItems:"center",gap:12,marginBottom:16}}><div style={{flex:1,height:4,background:C.border,borderRadius:2,overflow:"hidden"}}><div style={{width:`${(i/cards.length)*100}%`,height:"100%",background:C.accent2,borderRadius:2,transition:"width .3s"}}/></div><span style={{fontFamily:"Montserrat,sans-serif",fontSize:13,color:C.muted,fontWeight:600}}>{i+1}/{cards.length}</span></div><div style={{display:"flex",justifyContent:"space-between",marginBottom:20}}><span style={{fontFamily:"Montserrat,sans-serif",fontSize:10,fontWeight:600,letterSpacing:2,color:C.accent2}}>{bd.e} {bd.n}</span><Cn n={coins}/></div><div style={{flex:1,display:"flex",flexDirection:"column",justifyContent:"center",maxWidth:420,margin:"0 auto",width:"100%",opacity:am?0:1,transform:am?"translateX(-40px)":"none",transition:"all .3s"}}><div style={{background:"#fff",borderRadius:16,border:`1px solid ${C.border}`,overflow:"hidden",marginBottom:24}}><div style={{padding:"12px 20px",borderBottom:`1px solid ${C.border}`,display:"flex",alignItems:"center",gap:8}}><span style={{fontSize:16}}>{c.cat}</span><span style={{fontFamily:"Montserrat,sans-serif",fontSize:10,fontWeight:600,letterSpacing:1.5,color:C.muted,textTransform:"uppercase"}}>{c.tag}</span></div><div style={{padding:"20px 20px 12px"}}><h3 style={{fontFamily:"Cormorant Garamond,serif",fontSize:22,fontWeight:600,color:C.ink,margin:0,lineHeight:1.3}}>{c.hook}</h3></div><div style={{padding:"0 20px 16px"}}><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:15,color:C.ink+"cc",margin:0,lineHeight:1.6}}>{c.body}</p></div>{c.deep&&<div style={{padding:"0 20px 20px"}}>{!exp?<button onClick={()=>sexp(true)} style={{background:"transparent",border:"none",color:C.accent3,cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontSize:12,fontWeight:600,padding:0}}>Детальніше ↓</button>:<div style={{background:C.accent3+"08",borderRadius:8,padding:"12px 14px"}}><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.ink+"bb",margin:0,lineHeight:1.6}}>{c.deep}</p></div>}</div>}</div><div style={{display:"flex",gap:12}}><button onClick={()=>ans(true)} style={{flex:1,background:"#fff",border:`2px solid ${C.accent2}`,borderRadius:12,padding:"18px",cursor:"pointer",textAlign:"center"}}><span style={{fontSize:28,display:"block",marginBottom:4}}>✨</span><span style={{fontFamily:"Montserrat,sans-serif",fontSize:14,fontWeight:600,color:C.accent2}}>Знав!</span></button><button onClick={()=>ans(false)} style={{flex:1,background:"#fff",border:`2px solid ${C.accent}`,borderRadius:12,padding:"18px",cursor:"pointer",textAlign:"center"}}><span style={{fontSize:28,display:"block",marginBottom:4}}>🤯</span><span style={{fontFamily:"Montserrat,sans-serif",fontSize:14,fontWeight:600,color:C.accent}}>Не знав!</span></button></div></div><BNav a="learn" go={go}/></div>}

function IQQuiz({badgeIdx,onD}){const bd=BADGE_DATA[badgeIdx];const qs=bd?bd.quiz:[];const[i,si]=useState(0);const[sc,ssc]=useState(0);const[sel,ssel]=useState(null);const q=qs[i];if(!q)return null;const pk=j=>{ssel(j);const ok=j===q.ok;track("iqquiz_answer",{badge:bd?.id,q:i+1,question:q.q,answer:q.opts[j],correct:ok});if(ok)ssc(s=>s+1);setTimeout(()=>{if(i+1>=qs.length){track("iqquiz_complete",{badge:bd?.id,score:ok?sc+1:sc});onD(ok?sc+1:sc)}else{si(i+1);ssel(null)}},1200)};return <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",padding:"24px"}}><div style={{display:"flex",alignItems:"center",gap:12,marginBottom:16}}><div style={{flex:1,height:4,background:C.border,borderRadius:2,overflow:"hidden"}}><div style={{width:`${(i/qs.length)*100}%`,height:"100%",background:C.gold,borderRadius:2,transition:"width .3s"}}/></div><span style={{fontFamily:"Montserrat,sans-serif",fontSize:13,color:C.muted,fontWeight:600}}>{i+1}/{qs.length}</span></div><div style={{fontFamily:"Montserrat,sans-serif",fontSize:10,fontWeight:600,letterSpacing:2,color:C.gold,textAlign:"center",marginBottom:20}}>🧠 {bd.e} {bd.n}</div><div style={{flex:1,display:"flex",flexDirection:"column",justifyContent:"center",maxWidth:420,margin:"0 auto",width:"100%"}}><div style={{background:"#fff",borderRadius:14,padding:"20px",border:`1px solid ${C.border}`,marginBottom:16}}><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:18,color:C.ink,margin:0,lineHeight:1.5}}>{q.q}</p></div><div style={{display:"flex",flexDirection:"column",gap:8}}>{q.opts.map((o,j)=>{const iS=sel===j,isOk=j===q.ok,sh=sel!==null;let bg="#fff",bc=C.border,tc=C.ink;if(sh&&isOk){bg=C.accent2+"15";bc=C.accent2;tc=C.accent2}if(sh&&iS&&!isOk){bg="#e74c3c15";bc="#e74c3c";tc="#e74c3c"}return <button key={j} onClick={()=>sel===null&&pk(j)} style={{background:bg,border:`2px solid ${bc}`,borderRadius:12,padding:"14px 18px",cursor:sel===null?"pointer":"default",fontFamily:"Cormorant Garamond,serif",fontSize:16,color:tc,textAlign:"left",transition:"all .2s"}}>{o}{sh&&isOk?" ✅":""}{sh&&iS&&!isOk?" ❌":""}</button>})}</div></div></div>}

function RecPop({badgeIdx,onC}){const bd=BADGE_DATA[badgeIdx];const r=bd?.recipe;if(!r)return null;return <div style={{position:"fixed",inset:0,zIndex:200,background:"rgba(0,0,0,.5)",overflow:"auto"}} onClick={onC}><div onClick={e=>e.stopPropagation()} style={{background:C.paper,margin:"40px auto",maxWidth:420,borderRadius:20,overflow:"hidden"}}><div style={{background:C.ink,padding:"24px",textAlign:"center"}}><span style={{fontSize:48}}>{r.e}</span><h2 style={{fontFamily:"Cormorant Garamond,serif",fontSize:24,color:C.paper,margin:"8px 0 4px"}}>{r.t}</h2><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.gold,margin:0,fontStyle:"italic"}}>{r.sub}</p></div><div style={{padding:"20px"}}><div style={{background:C.accent2+"12",borderRadius:10,padding:"12px 16px",marginBottom:16}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:10,fontWeight:600,letterSpacing:1.5,color:C.accent2,margin:"0 0 6px"}}>ЧОМУ ЦЕ ПРАЦЮЄ</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.ink,margin:0,lineHeight:1.5}}>{r.why}</p></div><p style={{fontFamily:"Montserrat,sans-serif",fontSize:10,fontWeight:600,letterSpacing:1.5,color:C.muted,margin:"0 0 8px"}}>ІНГРЕДІЄНТИ</p>{r.ing.map((x,i)=><p key={i} style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.ink,margin:"4px 0",paddingLeft:8,borderLeft:`2px solid ${C.border}`}}>{typeof x==="string"?x:`${x.q} ${x.n}`}</p>)}<p style={{fontFamily:"Montserrat,sans-serif",fontSize:10,fontWeight:600,letterSpacing:1.5,color:C.muted,margin:"16px 0 8px"}}>КРОКИ</p>{r.steps.map((s,i)=><div key={i} style={{marginBottom:12}}><div style={{display:"flex",gap:8}}><span style={{fontFamily:"Montserrat,sans-serif",fontSize:11,fontWeight:700,color:C.accent}}>{i+1}</span><span style={{fontFamily:"Montserrat,sans-serif",fontSize:12,fontWeight:600,color:C.ink}}>{s.t}</span></div><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.ink+"cc",margin:"2px 0 2px 20px"}}>{s.d}</p><p style={{fontFamily:"Montserrat,sans-serif",fontSize:11,color:C.accent2,margin:"2px 0 0 20px",fontStyle:"italic"}}>⚗ {s.s}</p></div>)}{r.tip&&<div style={{background:C.gold+"0f",borderRadius:10,padding:"12px 16px",marginTop:8}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:10,fontWeight:600,color:C.gold,margin:"0 0 4px"}}>💡 ПОРАДА</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.ink,margin:0}}>{r.tip}</p></div>}<button onClick={onC} style={{width:"100%",background:C.ink,color:C.paper,border:"none",borderRadius:10,padding:"14px",cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontSize:14,fontWeight:600,marginTop:12}}>Закрити</button></div></div></div>}

function LDone({stats,badgeIdx,onBack,onRec}){return <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"40px 24px",textAlign:"center"}}><div style={{fontSize:56,marginBottom:16}}>📚</div><h2 style={{fontFamily:"Cormorant Garamond,serif",fontSize:24,color:C.ink,margin:"0 0 4px"}}>Навчання завершено</h2><p style={{fontFamily:"Montserrat,sans-serif",fontSize:13,color:C.muted,margin:"0 0 20px"}}>Знав: {stats.knew} · Нового: {stats.didnt}</p>{BADGE_DATA[badgeIdx]?.recipe&&<button onClick={onRec} style={{background:"#fff",borderRadius:14,border:`1px solid ${C.border}`,padding:"16px",marginBottom:16,maxWidth:320,width:"100%",cursor:"pointer",textAlign:"left"}}><div style={{display:"flex",alignItems:"center",gap:10}}><span style={{fontSize:28}}>{BADGE_DATA[badgeIdx].recipe.e}</span><div><p style={{fontFamily:"Montserrat,sans-serif",fontSize:9,fontWeight:600,letterSpacing:1.5,color:C.accent,margin:0}}>РЕЦЕПТ</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:16,fontWeight:600,color:C.ink,margin:0}}>{BADGE_DATA[badgeIdx].recipe.t}</p></div></div></button>}{stats.allDone&&<div style={{background:C.gold+"15",borderRadius:12,padding:"12px 20px",marginBottom:16,maxWidth:320}}><p style={{fontFamily:"Montserrat,sans-serif",fontSize:13,color:C.gold,margin:0,fontWeight:600}}>🧠 Квіз розблоковано!</p></div>}<button onClick={onBack} style={{background:C.ink,color:C.paper,border:"none",borderRadius:10,padding:"14px 36px",fontFamily:"Cormorant Garamond,serif",fontSize:18,cursor:"pointer"}}>{stats.allDone?"Пройти квіз →":"До профілю →"}</button></div>}

function AtlasHome({go,goAtlas}){useEffect(()=>{track("page_view",{page:"atlas"})},[]);return <div style={{minHeight:"100vh",padding:"24px 24px 90px"}}><h2 style={{fontFamily:"Cormorant Garamond,serif",fontSize:28,color:C.ink,margin:"40px 0 12px",textAlign:"center"}}>🗺️ Кулінарний Атлас</h2><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:16,color:C.muted,fontStyle:"italic",textAlign:"center",margin:"0 0 24px"}}>Один продукт — цілий всесвіт</p><button onClick={goAtlas} style={{width:"100%",background:"#fff",borderRadius:14,border:`1px solid ${C.border}`,padding:"20px",marginBottom:12,cursor:"pointer",textAlign:"left"}}><div style={{display:"flex",alignItems:"center",gap:12}}><span style={{fontSize:36}}>🥩</span><div><h3 style={{fontFamily:"Cormorant Garamond,serif",fontSize:18,color:C.ink,margin:0}}>Яловичина</h3><p style={{fontFamily:"Montserrat,sans-serif",fontSize:11,color:C.accent2,margin:0}}>6 груп · 10 трансформацій</p></div></div></button>{["🐔 Курятина","🐟 Лосось","🥚 Яйця","🍄 Гриби"].map((p,i)=><div key={i} style={{background:C.paper2,borderRadius:14,border:`1px solid ${C.border}`,padding:"16px 20px",marginBottom:8,opacity:.5}}><span style={{fontFamily:"Cormorant Garamond,serif",fontSize:16,color:C.muted}}>{p} — скоро</span></div>)}<BNav a="atlas" go={go}/></div>}

function AtlasProduct({go}){const[openG,sog]=useState(null);const p=BEEF_PASSPORT;
return <div style={{minHeight:"100vh",padding:"0 0 90px"}}><div style={{background:C.ink,padding:"24px 20px 20px"}}><button onClick={()=>go("atlas")} style={{background:"transparent",border:"none",color:C.muted,cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontSize:12,marginBottom:12}}>← Назад</button><div style={{textAlign:"center"}}><span style={{fontSize:48}}>🥩</span><h2 style={{fontFamily:"Cormorant Garamond,serif",fontSize:28,color:C.paper,margin:"8px 0 4px"}}>Яловичина</h2><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:14,color:C.gold,margin:0,fontStyle:"italic"}}>{p.tagline}</p><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:13,color:C.paper+"bb",margin:"10px auto 0",maxWidth:360,lineHeight:1.5}}>{p.desc}</p></div></div>
<div style={{padding:"16px 20px"}}>{BEEF_GROUPS.map(g=><div key={g.id} style={{marginBottom:12}}><button onClick={()=>sog(openG===g.id?null:g.id)} style={{width:"100%",background:C.paper2,border:`1px solid ${C.border}`,borderRadius:openG===g.id?"12px 12px 0 0":12,padding:"14px 16px",cursor:"pointer",display:"flex",alignItems:"center",gap:10,textAlign:"left"}}><span style={{fontSize:22}}>{g.em}</span><div style={{flex:1}}><span style={{fontFamily:"Montserrat,sans-serif",fontSize:13,fontWeight:600,color:C.ink}}>{g.label}</span><span style={{fontFamily:"Montserrat,sans-serif",fontSize:10,color:C.muted,marginLeft:8}}>{g.transforms.length}</span></div><span style={{color:C.muted}}>{openG===g.id?"▲":"▼"}</span></button>
{openG===g.id&&<div style={{background:"#fff",border:`1px solid ${C.border}`,borderTop:"none",borderRadius:"0 0 12px 12px",padding:"12px"}}><p style={{fontFamily:"Cormorant Garamond,serif",fontSize:13,color:C.muted,fontStyle:"italic",margin:"0 0 12px"}}>{g.desc}</p>{g.transforms.map((t,ti)=><div key={ti} style={{background:t.f?C.accent+"08":"transparent",border:`1px solid ${t.f?C.accent+"30":C.border}`,borderRadius:10,padding:"14px",marginBottom:8}}>
<h4 style={{fontFamily:"Cormorant Garamond,serif",fontSize:17,color:C.ink,margin:0}}>{t.f&&"★ "}{t.title}</h4>
<p style={{fontFamily:"Montserrat,sans-serif",fontSize:10,color:C.muted,margin:"2px 0 0"}}>{t.method} · {t.cut} · {t.time} · {t.level}</p>
<p style={{fontFamily:"Cormorant Garamond,serif",fontSize:13,color:C.ink+"cc",margin:"6px 0 0",lineHeight:1.4}}>{t.tag}</p>
{t.parts&&<p style={{fontFamily:"Montserrat,sans-serif",fontSize:10,color:C.accent2,margin:"4px 0 0"}}>🥩 {t.parts}</p>}
</div>)}</div>}
</div>)}</div>
<BNav a="atlas" go={go}/></div>}

/* ═══ APP ═══ */
export default function App(){
  useEffect(()=>{document.title="Кулінарний Оракул"},[]);
  const[scr,ss]=useState("intro");
  const[arch,sa]=useState(null);
  const[coins,sc]=useState(0);
  const[iq,si]=useState(0);
  const[learned,sl]=useState(0);
  const[bdgs,sb]=useState(BADGE_DATA.map(b=>({...b,done:false,qs:0})));
  const[curBdg,scb]=useState(0);
  const[pop,sp]=useState(null);
  const[actB,sab]=useState(null);
  const[actBi,sabi]=useState(0);
  const[lSt,sls]=useState(null);
  const[showRec,ssr]=useState(false);
  const[archExp,sae]=useState(true);
  const[user,setUser]=useState(null);
  const[saving,setSaving]=useState(false);
  const[showShare,setShowShare]=useState(false);
  const[showAuth,setShowAuth]=useState(false);

  // Auth: listen for login/logout
  useEffect(()=>{
    supabase.auth.getSession().then(({data:{session}})=>{
      setUser(session?.user||null);
      if(session?.user) loadProfile(session.user.id);
    });
    const {data:{subscription}}=supabase.auth.onAuthStateChange((_,session)=>{
      setUser(session?.user||null);
      if(session?.user) loadProfile(session.user.id);
    });
    return ()=>subscription.unsubscribe();
  },[]);

  // Load profile from Supabase
  const loadProfile=async(uid)=>{
    try{
      const{data}=await supabase.from("profiles").select("*").eq("id",uid).single();
      if(data){
        if(data.archetype_id){
          const a=ARCH.find(x=>x.id===data.archetype_id);
          if(a){sa(a);ss("profile")}
        }
        if(data.coins)sc(data.coins);
        if(data.iq)si(data.iq);
        if(data.learned)sl(data.learned);
        if(data.current_badge!=null)scb(data.current_badge);
        if(data.badges&&Array.isArray(data.badges)&&data.badges.length>0){
          sb(BADGE_DATA.map((b,i)=>{
            const saved=data.badges[i];
            return saved?{...b,done:saved.done||false,qs:saved.qs||0}:{...b,done:false,qs:0};
          }));
        }
      }
    }catch(e){console.log("load err",e)}
  };

  // Save profile to Supabase (debounced)
  const saveProfile=useCallback(async(overrides={})=>{
    if(!user)return;
    setSaving(true);
    try{
      const payload={
        archetype_id:arch?.id||null,
        coins,iq,learned,current_badge:curBdg,
        badges:bdgs.map(b=>({done:b.done,qs:b.qs})),
        updated_at:new Date().toISOString(),
        ...overrides
      };
      // Save spectrum in badges field as a side-channel since we don't have a column for it
      // Better approach: just include in archetype state
      await supabase.from("profiles").update(payload).eq("id",user.id);
    }catch(e){console.log("save err",e)}
    setSaving(false);
  },[user,arch,coins,iq,learned,curBdg,bdgs]);

  // Auto-save when key state changes
  useEffect(()=>{
    if(user&&arch) saveProfile();
  },[arch?.id,coins,iq,learned,curBdg,JSON.stringify(bdgs.map(b=>b.done+":"+b.qs))]);

  // Google login
  const login=async()=>{
    await supabase.auth.signInWithOAuth({provider:"google",options:{redirectTo:window.location.origin}});
  };
  const logout=async()=>{
    await supabase.auth.signOut();
    setUser(null);
  };

  const go=s=>{ss(s);sab(null);window.scrollTo(0,0)};
  const addC=(n,t)=>{sc(c=>c+n);sp({amt:n,txt:t})};

  // Dashboard access: /dashboard or ?admin
  useEffect(()=>{
    if(window.location.hash==="#dashboard"||window.location.search.includes("admin"))ss("dashboard");
  },[]);

  // Auth button component
  const AuthBtn=()=>user?
    <button onClick={logout} style={{position:"fixed",top:8,right:8,zIndex:150,background:"#fff",border:`1px solid ${C.border}`,borderRadius:20,padding:"6px 14px",cursor:"pointer",display:"flex",alignItems:"center",gap:6}}>
      <span style={{fontFamily:"Montserrat,sans-serif",fontSize:10,color:C.muted}}>{user.email?.split("@")[0]}</span>
      <span style={{fontSize:10,color:C.muted}}>↗</span>
    </button>:
    <button onClick={login} style={{position:"fixed",top:8,right:8,zIndex:150,background:C.ink,color:C.paper,border:"none",borderRadius:20,padding:"6px 14px",cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontSize:11}}>
      Увійти
    </button>;

  return <div style={{minHeight:"100vh",background:C.paper}}>
    <style>{`@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;0,700;1,400&family=Montserrat:wght@400;500;600;700&display=swap');*{box-sizing:border-box;margin:0;padding:0}body{background:${C.paper}}button:active{transform:scale(.97)!important}`}</style>
    {scr!=="dashboard"&&<AuthBtn/>}
    {saving&&<div style={{position:"fixed",top:12,left:"50%",transform:"translateX(-50%)",zIndex:200,background:C.accent2,color:"#fff",borderRadius:12,padding:"4px 12px",fontFamily:"Montserrat,sans-serif",fontSize:10}}>💾</div>}
    {pop&&<Pop amt={pop.amt} txt={pop.txt} onD={()=>sp(null)}/>}
    {showRec&&<RecPop badgeIdx={curBdg} onC={()=>ssr(false)}/>}
    {showAuth&&<AuthPrompt onLogin={()=>{setShowAuth(false);login()}} onSkip={()=>{setShowAuth(false);setShowShare(true)}}/>}
    {showShare&&arch&&<ShareCard arch={arch} onC={()=>setShowShare(false)}/>}
    {actB&&scr==="profile"&&<BModal b={actB} bi={actBi} curBdg={curBdg} onL={()=>{sab(null);scb(actBi);go("learn")}} onQ={()=>{sab(null);scb(actBi);go("iqquiz")}} onC={()=>sab(null)}/>}
    {scr==="intro"&&<Intro go={()=>{addC(100,"Ласкаво просимо!");setTimeout(()=>go("archquiz"),1900)}}/>}
    {scr==="archquiz"&&<AQuiz onD={({answers,questions})=>{const r=calc(answers,questions);sa(r);track("archetype_result",{archetype:r.id,name:r.n});addC(50,"Архетип визначено!");setTimeout(()=>{go("profile");if(!user)setShowAuth(true);else setShowShare(true)},1900)}}/>}
    {scr==="profile"&&arch&&<ProfileScr arch={arch} coins={coins} bdgs={bdgs} iq={iq} learned={learned} curBdg={curBdg} expanded={archExp} setExpanded={sae} go={go} onLearn={(idx)=>{sae(false);if(idx!=null&&idx>=0)scb(idx);track("learn_navigate",{badge:BADGE_DATA[idx??curBdg]?.id});go("learn")}} onBdg={(b,i)=>{sab(b);sabi(i)}} onShare={()=>{track("share_open");setShowShare(true)}}/>}
    {scr==="learn"&&<Learn badgeIdx={curBdg} coins={coins} setCn={sc} go={go} onD={s=>{sls(s);sl(l=>l+s.total);go("ldone")}}/>}
    {scr==="ldone"&&lSt&&<LDone stats={lSt} badgeIdx={curBdg} onRec={()=>ssr(true)} onBack={()=>{if(lSt.allDone){go("iqquiz")}else go("profile")}}/>}
    {scr==="iqquiz"&&<IQQuiz badgeIdx={curBdg} onD={score=>{const g=score*20;si(v=>v+g);sb(bs=>bs.map((b,i)=>i===curBdg?{...b,done:true,qs:score}:b));scb(c=>Math.min(c+1,BADGE_DATA.length-1));sae(false);track("badge_earned",{badge:bdgs[curBdg]?.id,name:bdgs[curBdg]?.n,score});sp({amt:0,txt:`${bdgs[curBdg]?.e} Бейдж "${bdgs[curBdg]?.n}" отримано!`});setTimeout(()=>go("profile"),1900)}}/>}
    {scr==="atlas"&&<AtlasHome go={go} goAtlas={()=>{track("atlas_product",{product:"beef"});go("atlas-product")}}/>}
    {scr==="atlas-product"&&<AtlasProduct go={go}/>}
    {scr==="dashboard"&&<Dashboard go={go}/>}
  </div>
}

/* ═══ DASHBOARD ═══ */
function Dashboard({go}){
  const[allEvents,setAllEvents]=useState([]);const[allProfiles,setAllProfiles]=useState([]);const[loading,setLoading]=useState(true);
  // Filter: "v2" (тільки нова версія, з 2026-04-29), "all" (всі дані)
  const[filter,setFilter]=useState("v2");
  const V2_DATE="2026-04-29T00:00:00Z";
  useEffect(()=>{
    (async()=>{
      const[e,p]=await Promise.all([
        supabase.from("events").select("*").order("created_at",{ascending:false}).limit(10000),
        supabase.from("profiles").select("*")
      ]);
      setAllEvents(e.data||[]);setAllProfiles(p.data||[]);setLoading(false);
    })();
  },[]);

  if(loading)return <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:"#1a1a2e"}}><p style={{color:"#fff",fontFamily:"Montserrat,sans-serif"}}>Завантаження...</p></div>;

  // Apply filter
  const events=filter==="v2"?allEvents.filter(e=>e.created_at>=V2_DATE):allEvents;
  const profiles=filter==="v2"?allProfiles.filter(p=>p.updated_at>=V2_DATE||p.created_at>=V2_DATE):allProfiles;

  // Helpers
  const evOf=ev=>events.filter(e=>e.event===ev);
  const uniqueOf=ev=>{const uids=new Set();evOf(ev).forEach(e=>{uids.add(e.user_id||e.id)});return uids.size};
  const totalOf=ev=>evOf(ev).length;
  const pageViews=events.filter(e=>e.event==="page_view"&&e.data?.page==="intro");
  const atlasViews=events.filter(e=>e.event==="page_view"&&e.data?.page==="atlas");

  // Funnel with unique + total
  const funnelSteps=[
    {l:"Відкрили додаток",uniq:Math.max(new Set(pageViews.map(e=>e.user_id||e.id)).size,uniqueOf("quiz_start")),total:Math.max(pageViews.length,totalOf("quiz_start"))},
    {l:"Почали квіз",uniq:uniqueOf("quiz_start"),total:totalOf("quiz_start")},
    {l:"Завершили квіз",uniq:uniqueOf("archetype_result"),total:totalOf("archetype_result")},
    {l:"Зареєструвались",uniq:profiles.length,total:profiles.length},
    {l:"Почали навчання",uniq:uniqueOf("learn_start"),total:totalOf("learn_start")},
    {l:"Завершили навчання",uniq:uniqueOf("learn_complete"),total:totalOf("learn_complete")},
    {l:"Отримали бейдж",uniq:uniqueOf("badge_earned"),total:totalOf("badge_earned")},
    {l:"Відкрили Атлас",uniq:new Set(atlasViews.map(e=>e.user_id||e.id)).size,total:atlasViews.length},
    {l:"Поділились",uniq:uniqueOf("share_open"),total:totalOf("share_open")},
  ];

  // Archetypes
  const archCounts={};
  evOf("archetype_result").forEach(e=>{const n=e.data?.name||"?";archCounts[n]=(archCounts[n]||0)+1});
  const archSorted=Object.entries(archCounts).sort((a,b)=>b[1]-a[1]);

  // Quiz answers per question
  const quizAnswers={};
  evOf("archquiz_answer").forEach(e=>{const q=e.data?.question;const ch=e.data?.choice;const ax=e.data?.axis;if(q){if(!quizAnswers[q])quizAnswers[q]={question:q,axis:ax,answers:{},users:new Set()};quizAnswers[q].answers[ch]=(quizAnswers[q].answers[ch]||0)+1;quizAnswers[q].users.add(e.user_id||e.id)}});

  // Learning cards
  const learnCards={};
  evOf("learn_card").forEach(e=>{const k=`${e.data?.badge}:${e.data?.card}`;if(!learnCards[k])learnCards[k]={badge:e.data?.badge,card:e.data?.card,hook:e.data?.hook,knew:0,didnt:0,users:new Set()};if(e.data?.knew)learnCards[k].knew++;else learnCards[k].didnt++;learnCards[k].users.add(e.user_id||e.id)});

  // IQ quiz answers
  const iqAnswers={};
  evOf("iqquiz_answer").forEach(e=>{const k=`${e.data?.badge}:${e.data?.q}`;if(!iqAnswers[k])iqAnswers[k]={badge:e.data?.badge,q:e.data?.q,question:e.data?.question,correct:0,wrong:0,users:new Set()};if(e.data?.correct)iqAnswers[k].correct++;else iqAnswers[k].wrong++;iqAnswers[k].users.add(e.user_id||e.id)});

  // Styles
  const S={bg:"#1a1a2e",card:"#16213e",accent:"#0f3460",blue:"#53a8e2",green:"#4ecca3",red:"#e74c3c",yellow:"#f39c12",orange:"#e67e22",text:"#eee",muted:"#888",font:"Montserrat,sans-serif"};
  const Card=({title,children})=><div style={{background:S.card,borderRadius:12,padding:"16px",marginBottom:12}}><h3 style={{fontFamily:S.font,fontSize:12,fontWeight:600,letterSpacing:1.5,color:S.muted,marginBottom:12,textTransform:"uppercase"}}>{title}</h3>{children}</div>;

  const funnelMax=Math.max(...funnelSteps.map(f=>f.uniq),1);

  return <div style={{minHeight:"100vh",background:S.bg,padding:"20px",maxWidth:600,margin:"0 auto"}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
      <h1 style={{fontFamily:"Cormorant Garamond,serif",fontSize:24,color:S.text,margin:0}}>📊 Дашборд</h1>
      <button onClick={()=>go("profile")} style={{background:S.card,border:"none",color:S.muted,borderRadius:8,padding:"6px 12px",cursor:"pointer",fontFamily:S.font,fontSize:11}}>← Назад</button>
    </div>
    <div style={{display:"flex",gap:6,marginBottom:18}}>
      <button onClick={()=>setFilter("v2")} style={{flex:1,background:filter==="v2"?S.blue:S.card,border:"none",color:filter==="v2"?"#fff":S.muted,borderRadius:8,padding:"8px",cursor:"pointer",fontFamily:S.font,fontSize:11,fontWeight:600}}>🔮 Оракул (v2)</button>
      <button onClick={()=>setFilter("all")} style={{flex:1,background:filter==="all"?S.blue:S.card,border:"none",color:filter==="all"?"#fff":S.muted,borderRadius:8,padding:"8px",cursor:"pointer",fontFamily:S.font,fontSize:11,fontWeight:600}}>📚 Всі дані</button>
    </div>

    <Card title="Ключові метрики">
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:6}}>
        {[{l:"Юзерів",n:profiles.length,c:S.blue},{l:"Квізів",n:totalOf("archetype_result"),c:S.green},{l:"Бейджів",n:totalOf("badge_earned"),c:S.yellow},{l:"Подій",n:events.length,c:S.orange}].map((m,i)=>
          <div key={i} style={{background:S.accent,borderRadius:8,padding:"10px 4px",textAlign:"center"}}>
            <div style={{fontFamily:S.font,fontSize:22,fontWeight:700,color:m.c}}>{m.n}</div>
            <div style={{fontFamily:S.font,fontSize:8,color:S.muted,marginTop:2}}>{m.l}</div>
          </div>
        )}
      </div>
    </Card>

    <Card title="Воронка">
      <div style={{display:"grid",gridTemplateColumns:"1fr 60px 60px 60px",gap:0,marginBottom:8}}>
        <span style={{fontFamily:S.font,fontSize:9,color:S.muted,fontWeight:600}}>КРОК</span>
        <span style={{fontFamily:S.font,fontSize:9,color:S.muted,fontWeight:600,textAlign:"right"}}>УНІК.</span>
        <span style={{fontFamily:S.font,fontSize:9,color:S.muted,fontWeight:600,textAlign:"right"}}>ВСЬОГО</span>
        <span style={{fontFamily:S.font,fontSize:9,color:S.muted,fontWeight:600,textAlign:"right"}}>КОНВ.%</span>
      </div>
      {funnelSteps.map((f,i)=>{
        const prev=i>0?funnelSteps[i-1].uniq:f.uniq;
        const conv=prev>0?Math.round((f.uniq/prev)*100):0;
        const barW=Math.max((f.uniq/funnelMax)*100,2);
        const color=i<3?S.blue:i<6?S.green:S.yellow;
        return <div key={i} style={{marginBottom:6}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 60px 60px 60px",gap:0,marginBottom:3}}>
            <span style={{fontFamily:S.font,fontSize:11,color:S.text}}>{f.l}</span>
            <span style={{fontFamily:S.font,fontSize:12,fontWeight:700,color,textAlign:"right"}}>{f.uniq}</span>
            <span style={{fontFamily:S.font,fontSize:11,color:S.muted,textAlign:"right"}}>{f.total}</span>
            <span style={{fontFamily:S.font,fontSize:11,color:i===0?"transparent":conv>=50?S.green:conv>=20?S.yellow:S.red,textAlign:"right"}}>{i===0?"":conv+"%"}</span>
          </div>
          <div style={{height:4,background:S.accent,borderRadius:2,overflow:"hidden"}}><div style={{width:`${barW}%`,height:"100%",background:color,borderRadius:2}}/></div>
        </div>
      })}
    </Card>

    {archSorted.length>0&&<Card title="Розподіл архетипів">
      {archSorted.map(([name,count],i)=><div key={i} style={{marginBottom:6}}>
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:2}}>
          <span style={{fontFamily:S.font,fontSize:11,color:S.text}}>{name}</span>
          <span style={{fontFamily:S.font,fontSize:11,fontWeight:700,color:S.green}}>{count} <span style={{color:S.muted,fontWeight:400}}>({Math.round(count/totalOf("archetype_result")*100)}%)</span></span>
        </div>
        <div style={{height:4,background:S.accent,borderRadius:2,overflow:"hidden"}}><div style={{width:`${(count/archSorted[0][1])*100}%`,height:"100%",background:S.green,borderRadius:2}}/></div>
      </div>)}
    </Card>}

    {Object.keys(quizAnswers).length>0&&<Card title="Квіз архетипу — відповіді по питаннях">
      {Object.entries(quizAnswers).map(([q,data])=>{
        const total=Object.values(data.answers).reduce((s,v)=>s+v,0);
        return <div key={q} style={{marginBottom:14,padding:"10px",background:S.accent,borderRadius:8}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:6,gap:8}}>
            <span style={{fontFamily:S.font,fontSize:10,color:S.text,flex:1}}>{data.question}{data.axis?` [${data.axis}]`:""}</span>
            <span style={{fontFamily:S.font,fontSize:9,color:S.muted,whiteSpace:"nowrap"}}>{data.users.size} юз.</span>
          </div>
          {Object.entries(data.answers).sort((a,b)=>b[1]-a[1]).map(([ans,cnt],i)=><div key={i} style={{marginBottom:4}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:2}}>
              <span style={{fontFamily:S.font,fontSize:10,color:S.text}}>{ans}</span>
              <span style={{fontFamily:S.font,fontSize:10,color:i===0?S.blue:S.muted}}>{cnt} ({Math.round(cnt/total*100)}%)</span>
            </div>
            <div style={{height:3,background:"#0a1628",borderRadius:2,overflow:"hidden"}}><div style={{width:`${(cnt/total)*100}%`,height:"100%",background:i===0?S.blue:S.muted+"60",borderRadius:2}}/></div>
          </div>)}
        </div>
      })}
    </Card>}

    {Object.keys(learnCards).length>0&&<Card title="Навчальні картки — знав / не знав">
      {Object.values(learnCards).sort((a,b)=>(a.badge+a.card).localeCompare(b.badge+b.card)).map((c,i)=>{
        const total=c.knew+c.didnt;const knewPct=total>0?Math.round(c.knew/total*100):0;
        return <div key={i} style={{marginBottom:6,padding:"8px 10px",background:S.accent,borderRadius:6}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
            <span style={{fontFamily:S.font,fontSize:9,color:S.text}}>{c.badge} #{c.card}: {c.hook?.slice(0,40)}</span>
            <span style={{fontFamily:S.font,fontSize:9,color:S.muted}}>{c.users.size} юз.</span>
          </div>
          <div style={{display:"flex",gap:6,alignItems:"center"}}>
            <div style={{flex:1,height:6,background:"#0a1628",borderRadius:3,overflow:"hidden",display:"flex"}}>
              <div style={{width:`${knewPct}%`,height:"100%",background:S.green}}/>
              <div style={{width:`${100-knewPct}%`,height:"100%",background:S.red}}/>
            </div>
            <span style={{fontFamily:S.font,fontSize:9,color:S.green,minWidth:28}}>✨{c.knew}</span>
            <span style={{fontFamily:S.font,fontSize:9,color:S.red,minWidth:28}}>🤯{c.didnt}</span>
          </div>
        </div>
      })}
    </Card>}

    {Object.keys(iqAnswers).length>0&&<Card title="IQ квіз — правильність по питаннях">
      {Object.values(iqAnswers).sort((a,b)=>(a.badge+a.q).localeCompare(b.badge+b.q)).map((q,i)=>{
        const total=q.correct+q.wrong;const pct=total>0?Math.round(q.correct/total*100):0;
        return <div key={i} style={{marginBottom:6,padding:"8px 10px",background:S.accent,borderRadius:6}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
            <span style={{fontFamily:S.font,fontSize:9,color:S.text}}>{q.badge} Q{q.q}: {q.question?.slice(0,40)}</span>
            <span style={{fontFamily:S.font,fontSize:9,color:S.muted}}>{q.users.size} юз.</span>
          </div>
          <div style={{display:"flex",gap:6,alignItems:"center"}}>
            <div style={{flex:1,height:6,background:"#0a1628",borderRadius:3,overflow:"hidden",display:"flex"}}>
              <div style={{width:`${pct}%`,height:"100%",background:S.green}}/>
              <div style={{width:`${100-pct}%`,height:"100%",background:S.red}}/>
            </div>
            <span style={{fontFamily:S.font,fontSize:9,color:S.green,minWidth:28}}>✅{q.correct}</span>
            <span style={{fontFamily:S.font,fontSize:9,color:S.red,minWidth:28}}>❌{q.wrong}</span>
            <span style={{fontFamily:S.font,fontSize:9,color:pct>=70?S.green:pct>=40?S.yellow:S.red,minWidth:28}}>{pct}%</span>
          </div>
        </div>
      })}
    </Card>}

    <Card title="Останні 30 подій">
      {events.filter(e=>e.event!=="page_view"||e.data?.page).slice(0,30).map((e,i)=><div key={i} style={{display:"flex",justifyContent:"space-between",padding:"3px 0",borderBottom:`1px solid ${S.accent}`}}>
        <span style={{fontFamily:S.font,fontSize:9,color:S.text}}>{e.event}{e.data?.page?" ("+e.data.page+")":""}{e.data?.choice?" → "+e.data.choice:""}{e.data?.name?" → "+e.data.name:""}</span>
        <span style={{fontFamily:S.font,fontSize:8,color:S.muted}}>{new Date(e.created_at).toLocaleString("uk")}</span>
      </div>)}
    </Card>
  </div>
}
